t.script:
document.addEventListener("DOMContentLoaded", function () {
    const linesContainer = document.getElementById("ajc_portal_lines");
    const addButton = document.getElementById("ajc_add_line_btn");
    const template = document.getElementById("ajc_portal_line_template");
    if (!linesContainer || !addButton || !template) {
        return;
    }

    const syncRow = (row) => {
        const gammeSelect = row.querySelector(".o_ajc_gamme_select");
        const serieSelect = row.querySelector(".o_ajc_serie_select");
        const modeleSelect = row.querySelector(".o_ajc_modele_select");
        if (!gammeSelect || !serieSelect || !modeleSelect) {
            return;
        }

        const gammeId = gammeSelect.value;
        let selectedSerieVisible = false;
        Array.from(serieSelect.options).forEach((option) => {
            if (!option.value) {
                option.hidden = false;
                return;
            }
            const visible = !gammeId || option.dataset.gammeId === gammeId;
            option.hidden = !visible;
            if (!visible && option.selected) {
                option.selected = false;
            }
            if (visible && option.selected) {
                selectedSerieVisible = true;
            }
        });
        if (!selectedSerieVisible) {
            serieSelect.value = "";
        }

        const serieId = serieSelect.value;
        let selectedModeleVisible = false;
        Array.from(modeleSelect.options).forEach((option) => {
            if (!option.value) {
                option.hidden = false;
                return;
            }
            const visible = !serieId || option.dataset.serieId === serieId;
            option.hidden = !visible;
            if (!visible && option.selected) {
                option.selected = false;
            }
            if (visible && option.selected) {
                selectedModeleVisible = true;
            }
        });
        if (!selectedModeleVisible) {
            modeleSelect.value = "";
        }
    };

    const refreshLabels = () => {
        Array.from(linesContainer.querySelectorAll(".o_ajc_portal_line")).forEach((row, index) => {
            const label = row.querySelector(".o_ajc_line_position");
            if (label) {
                label.textContent = String(index + 1);
            }
            const removeButton = row.querySelector(".o_ajc_remove_line");
            if (removeButton) {
                removeButton.disabled = linesContainer.querySelectorAll(".o_ajc_portal_line").length <= 1;
            }
        });
    };

    const initRow = (row) => {
        const gammeSelect = row.querySelector(".o_ajc_gamme_select");
        const serieSelect = row.querySelector(".o_ajc_serie_select");
        if (gammeSelect) {
            gammeSelect.addEventListener("change", () => syncRow(row));
        }
        if (serieSelect) {
            serieSelect.addEventListener("change", () => syncRow(row));
        }
        syncRow(row);
    };

    Array.from(linesContainer.querySelectorAll(".o_ajc_portal_line")).forEach(initRow);
    refreshLabels();

    addButton.addEventListener("click", function () {
        const indices = Array.from(linesContainer.querySelectorAll(".o_ajc_portal_line")).map((row) => parseInt(row.dataset.lineIndex || "0", 10)).filter((value) => !Number.isNaN(value));
        const nextIndex = indices.length ? Math.max.apply(null, indices) + 1 : 0;
        const nextSequence = (nextIndex + 1) * 10;
        const wrapper = document.createElement("div");
        wrapper.innerHTML = template.innerHTML
            .replace(/__INDEX__/g, String(nextIndex))
            .replace(/__DISPLAY__/g, String(linesContainer.querySelectorAll(".o_ajc_portal_line").length + 1))
            .replace(/__SEQUENCE__/g, String(nextSequence))
            .trim();
        const newRow = wrapper.firstElementChild;
        if (!newRow) {
            return;
        }
        linesContainer.appendChild(newRow);
        initRow(newRow);
        refreshLabels();
    });

    linesContainer.addEventListener("click", function (event) {
        const button = event.target.closest(".o_ajc_remove_line");
        if (!button) {
            return;
        }
        const rows = linesContainer.querySelectorAll(".o_ajc_portal_line");
        if (rows.length <= 1) {
            return;
        }
        const row = button.closest(".o_ajc_portal_line");
        if (row) {
            row.remove();
            refreshLabels();
        }
    });
});
